import React, { useContext } from 'react';
import { Routes, Route, Link, Navigate } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import { FaHome, FaCar, FaCalendarAlt, FaUsers, FaBuilding, FaChartBar } from 'react-icons/fa';
import SuperAdminDashboard from '../components/dashboard/SuperAdminDashboard';
import AdminDashboard from '../components/dashboard/AdminDashboard';
import BranchHeadDashboard from '../components/dashboard/BranchHeadDashboard';
import StaffDashboard from '../components/dashboard/StaffDashboard';
import './Dashboard.css';

const Dashboard = () => {
  const { user } = useContext(AuthContext);

  const getMenuItems = () => {
    const commonItems = [
      { path: '', icon: <FaHome />, label: 'Overview' },
      { path: 'bookings', icon: <FaCalendarAlt />, label: 'Bookings' }
    ];

    switch (user.role) {
      case 'super_admin':
        return [
          ...commonItems,
          { path: 'analytics', icon: <FaChartBar />, label: 'Analytics' },
          { path: 'users', icon: <FaUsers />, label: 'Users' },
          { path: 'branches', icon: <FaBuilding />, label: 'Branches' }
        ];
      case 'admin':
        return [
          ...commonItems,
          { path: 'branches', icon: <FaBuilding />, label: 'Branches' },
          { path: 'staff', icon: <FaUsers />, label: 'Staff' }
        ];
      case 'branch_head':
        return [
          ...commonItems,
          { path: 'cars', icon: <FaCar />, label: 'Cars' },
          { path: 'staff', icon: <FaUsers />, label: 'Staff' }
        ];
      case 'staff':
        return [
          ...commonItems,
          { path: 'create-booking', icon: <FaCalendarAlt />, label: 'Create Booking' }
        ];
      default:
        return commonItems;
    }
  };

  const getDashboardComponent = () => {
    switch (user.role) {
      case 'super_admin':
        return <SuperAdminDashboard />;
      case 'admin':
        return <AdminDashboard />;
      case 'branch_head':
        return <BranchHeadDashboard />;
      case 'staff':
        return <StaffDashboard />;
      default:
        return <Navigate to="/" />;
    }
  };

  return (
    <div className="dashboard">
      <div className="dashboard-layout">
        <aside className="dashboard-sidebar">
          <div className="sidebar-header">
            <h2>Dashboard</h2>
            <p className="user-role">{user.role.replace('_', ' ')}</p>
          </div>
          <nav className="sidebar-nav">
            {getMenuItems().map(item => (
              <Link
                key={item.path}
                to={`/dashboard/${item.path}`}
                className="nav-item"
              >
                {item.icon}
                <span>{item.label}</span>
              </Link>
            ))}
          </nav>
        </aside>

        <main className="dashboard-content">
          <Routes>
            <Route path="/" element={getDashboardComponent()} />
            <Route path="bookings" element={<div className="card"><h2>Bookings Management</h2></div>} />
            <Route path="cars" element={<div className="card"><h2>Cars Management</h2></div>} />
            <Route path="staff" element={<div className="card"><h2>Staff Management</h2></div>} />
            <Route path="branches" element={<div className="card"><h2>Branches Management</h2></div>} />
            <Route path="users" element={<div className="card"><h2>Users Management</h2></div>} />
            <Route path="analytics" element={<div className="card"><h2>Analytics</h2></div>} />
            <Route path="create-booking" element={<div className="card"><h2>Create Offline Booking</h2></div>} />
          </Routes>
        </main>
      </div>
    </div>
  );
};

export default Dashboard;
